mapper.update:
UPDATE a_generation_task
SET lease_until = #{leaseUntil}
WHERE id = #{id}
  AND status = 1
  AND locked_by = #{workerId}

mapper.select:
SELECT t.id AS id, t.biz_no AS bizNo, t.target_user_id AS userId, COALESCE(NULLIF(u.nickname, ''), u.email) AS userNickname, t.status AS status, t.model_config_id AS modelConfigId, t.word_limit_target AS wordLimitTarget, t.retry_count AS retryCount, t.locked_by AS lockedBy, t.locked_at AS lockedAt, t.lease_until AS leaseUntil, t.failed_reason AS failedReason, t.completed_at AS completedAt, t.created_at AS createdAt FROM a_generation_task t LEFT JOIN u_user u ON u.id = t.target_user_id AND u.is_deleted = 0 WHERE t.is_deleted = 0 AND t.status = #{status}
AND (t.biz_no LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.created_at DESC LIMIT #{offset}, #{limit}
